function showNewGameModal() {
  if (!credentials || !currentState) return;
  resetModalPresentation();
  $("#modalTitle").textContent = "新花园操作";
  const body = $("#modalBody");
  body.className = "danger-modal-body";
  body.innerHTML = "";

  const canMoveWithCat =
    currentState?.cat_state?.phase === "adopted" && Boolean(currentState?.cat?.name);
  let selectedMode = "new_game";

  const chooser = document.createElement("div");
  chooser.className = "danger-choice-grid";
  const newGameOption = document.createElement("button");
  newGameOption.type = "button";
  newGameOption.className = "danger-choice-btn active";
  newGameOption.innerHTML = "<strong>开启全新花园</strong><span>当前花园全部覆盖，从头开始新版开局。</span>";
  const moveWithCatOption = document.createElement("button");
  moveWithCatOption.type = "button";
  moveWithCatOption.className = "danger-choice-btn";
  moveWithCatOption.innerHTML = "<strong>带猫搬家</strong><span>只保留猫咪名字和已收养状态，其余进度重置。</span>";
  moveWithCatOption.disabled = !canMoveWithCat;
  chooser.append(newGameOption, moveWithCatOption);

  const disabledHint = document.createElement("p");
  disabledHint.className = "danger-disabled-hint";
  disabledHint.textContent = canMoveWithCat ? "" : "只有已经正式收养的猫咪可以一起搬家。";

  const warning = document.createElement("div");
  warning.className = "danger-warning-box";
  const warningTitle = document.createElement("strong");
  const warningList = document.createElement("ul");
  warningList.className = "danger-warning-list";
  warning.append(warningTitle, warningList);

  const prompt = document.createElement("p");
  prompt.className = "danger-confirm-copy";

  const input = document.createElement("input");
  input.type = "text";
  input.className = "danger-confirm-input";
  input.autocomplete = "off";
  input.placeholder = "请输入：确认";
  input.setAttribute("aria-label", "请输入确认文字");

  const hint = document.createElement("small");
  hint.className = "danger-confirm-hint";
  hint.textContent = "只有完整输入“确认”时才可执行。";

  const actions = document.createElement("div");
  actions.className = "modal-actions";
  const cancel = document.createElement("button");
  cancel.type = "button";
  cancel.className = "secondary-btn";
  cancel.textContent = "取消";
  cancel.addEventListener("click", closeModal);
  const submit = document.createElement("button");
  submit.type = "button";
  submit.className = "primary-btn danger-primary-btn";
  submit.disabled = true;
  submit.addEventListener("click", () => {
    if (input.value !== REQUIRED_CONFIRM_TEXT) return;
    if (selectedMode === "move_with_cat") {
      startMoveWithCat(submit);
      return;
    }
    startFreshGarden(submit);
  });
  actions.append(cancel, submit);

  function renderDangerMode() {
    newGameOption.classList.toggle("active", selectedMode === "new_game");
    moveWithCatOption.classList.toggle("active", selectedMode === "move_with_cat");
    warningList.innerHTML = "";

    if (selectedMode === "move_with_cat") {
      warningTitle.textContent = "这是不可撤销的搬家操作";
      for (const text of [
        "只保留猫咪名字和已收养状态。",
        "其余花园进度、物品、收藏和猫咪状态都会重置。",
        "操作不可撤销。",
      ]) {
        const item = document.createElement("li");
        item.textContent = text;
        warningList.append(item);
      }
      prompt.textContent = `请输入“${REQUIRED_CONFIRM_TEXT}”后，才可以带猫搬家。`;
      hint.textContent = `只有完整输入“${REQUIRED_CONFIRM_TEXT}”时才可执行。`;
      submit.textContent = "确认带猫搬家";
    } else {
      warningTitle.textContent = "这是不可撤销的覆盖操作";
      for (const text of [
        "当前花园全部内容会被覆盖。",
        "操作不可撤销。",
        "新花园不能与旧花园同时保留。",
      ]) {
        const item = document.createElement("li");
        item.textContent = text;
        warningList.append(item);
      }
      prompt.textContent = `请输入“${REQUIRED_CONFIRM_TEXT}”后，才可以开启全新花园。`;
      hint.textContent = `只有完整输入“${REQUIRED_CONFIRM_TEXT}”时才可执行。`;
      submit.textContent = "确认开启全新花园";
    }
    submit.disabled = input.value !== REQUIRED_CONFIRM_TEXT;
  }

  newGameOption.addEventListener("click", () => {
    selectedMode = "new_game";
    renderDangerMode();
  });
  if (canMoveWithCat) {
    moveWithCatOption.addEventListener("click", () => {
      selectedMode = "move_with_cat";
      renderDangerMode();
    });
  }

  input.placeholder = `请输入：${REQUIRED_CONFIRM_TEXT}`;
  input.setAttribute("aria-label", "请输入确认文字");

  input.addEventListener("input", () => {
    submit.disabled = input.value !== REQUIRED_CONFIRM_TEXT;
  });

  renderDangerMode();
  body.append(chooser, disabledHint, warning, prompt, input, hint, actions);
  $("#modal").classList.remove("hidden");
  input.focus();
}

function closeModal() {
  const closingModalKind = activeModalKind;
  stopNotesCooldownTimer();
  resetModalPresentation();
  if (closingModalKind === "update-announcement") {
    markUpdateAnnouncementSeen();
  }
  $("#modal").classList.add("hidden");
}


function openCollectionShortcut(){ showEncyclopediaModal(); }

async function initialize() {
  try {
    catalog = await requestJson("/api/catalog");
  } catch (error) {
    showToast(`加载游戏资料失败：${error.message}`);
    return;
  }

  credentials = loadCredentials();
  if (!credentials) {
    showWelcome();
    return;
  }
  showApp();
  try {
    await refreshGarden({ quiet: true });
  } catch {
    // refreshGarden 已处理无效钥匙与提示。
  }
}

$("#createForm").addEventListener("submit", async (event) => {
  event.preventDefault();
  const name = $("#gardenName").value.trim() || "我的小花园";
  try {
    await createGarden(name);
  } catch (error) {
    showToast(error.message);
  }
});

$("#importBtn").addEventListener("click", async () => {
  try {
    const parsed = JSON.parse($("#importKey").value.trim());
    if (!parsed.session_id || !parsed.garden_token) throw new Error("钥匙格式不完整");
    saveCredentials({ session_id: parsed.session_id, garden_token: parsed.garden_token });
    showApp();
    await refreshGarden();
    showToast("旧花园已经打开");
  } catch (error) {
    showToast(error.message || "无法打开这把花园存档码");
  }
});

$("#refreshBtn").addEventListener("click", () => refreshGarden().catch(() => {}));
$("#encyclopediaCard").addEventListener("click", openCollectionShortcut);
$("#encyclopediaCard").addEventListener("keydown", (event) => {
  if (event.key === "Enter" || event.key === " ") {
    event.preventDefault();
    openCollectionShortcut();
  }
});
$("#updateAnnouncementBtn").addEventListener("click", () => showUpdateAnnouncementModal());
$("#newGameBtn").addEventListener("click", showNewGameModal);
$("#keyBtn").addEventListener("click", showKeyModal);
$("#modalClose").addEventListener("click", closeModal);
$("#modal").addEventListener("click", (event) => { if (event.target.id === "modal") closeModal(); });

$("#backpackBtn").addEventListener("click", showBackpackModal);
$("#catBackpackBtn").addEventListener("click", showBackpackModal);
$("#harvestAllBtn").addEventListener("click", (event) => runCommand("harvest all", event.currentTarget));
$("#notesBtn").addEventListener("click", () => showNotesModal(1));

$("#commandForm").addEventListener("submit", (event) => {
  event.preventDefault();
  const command = $("#commandInput").value.trim();
  if (!command) return;
  $("#commandInput").value = "";
  runCommand(command);
});

$("#leaveBtn").addEventListener("click", () => {
  const confirmed = window.confirm("只会从这台设备移除钥匙，云端花园不会被删除。确认继续吗？");
  if (!confirmed) return;
  localStorage.removeItem(STORAGE_KEY);
  credentials = null;
  currentState = null;
  showWelcome();
  showToast("花园存档码已从当前设备移除");
});

for (const button of document.querySelectorAll(".tab-btn")) {
  button.addEventListener("click", () => {
    document.querySelectorAll(".tab-btn").forEach((item) => item.classList.remove("active"));
    document.querySelectorAll(".tab-content").forEach((item) => item.classList.remove("active"));
    button.classList.add("active");
    $(`#${button.dataset.tab}Tab`).classList.add("active");
  });
}

for (const button of document.querySelectorAll(".store-tab-btn")) {
  button.addEventListener("click", () => {
    document.querySelectorAll(".store-tab-btn").forEach((item) => item.classList.remove("active"));
    document.querySelectorAll(".store-pane").forEach((item) => item.classList.remove("active"));
    button.classList.add("active");
    const paneId = button.dataset.storeTab === "cat-items"
      ? "#catItemsStorePane"
      : "#seedsStorePane";
    $(paneId).classList.add("active");
  });
}

window.addEventListener("focus", () => {
  if (credentials && !isBusy) refreshGarden({ quiet: true }).catch(() => {});
});

document.addEventListener("visibilitychange", () => {
  if (document.visibilityState === "visible" && credentials && !isBusy) {
    refreshGarden({ quiet: true }).catch(() => {});
  }
});

setInterval(updateLiveCountdowns, 1_000);

setInterval(() => {
  if (document.visibilityState === "visible" && credentials && !isBusy) {
    refreshGarden({ quiet: true }).catch(() => {});
  }
}, 60_000);


for(const button of document.querySelectorAll('.sticky-tab')){
  button.addEventListener('click',()=>{
    document.querySelectorAll('.sticky-tab').forEach(b=>b.classList.toggle('active',b===button));
    document.querySelector('.garden-panel').classList.toggle('active',button.dataset.mainPane==='garden');
    document.querySelector('.store-panel').classList.toggle('active',button.dataset.mainPane==='store');
  });
}
for(const button of document.querySelectorAll('.cat-sticky-tab')){
  button.addEventListener('click',()=>{
    document.querySelectorAll('.cat-sticky-tab').forEach(b=>b.classList.toggle('active',b===button));
    document.querySelectorAll('.cat-switch-pane').forEach(p=>p.classList.remove('active'));
    const map={cat:'catContent',letters:'catLettersContent',collection:'catCollectionContent'};
    document.getElementById(map[button.dataset.catPane]).classList.add('active');
  });
}

